def run_ci_gate(test_cases, system_prompt, thresholds, model="gpt-4o-mini"):
    client = OpenAI()
    results = []
    for case in test_cases:
        resp = client.chat.completions.create(
            model=model, temperature=0,
            messages=[
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": case.input},
            ],
        )
        output = resp.choices[0].message.content
        em = 1.0 if output.strip() == (case.expected_output or "").strip() else 0.0
        results.append({"output": output, "exact_match": em})
    means = {m: sum(r[m] for r in results if r[m] is not None) / len(results)
             for m in thresholds}
    passed = all(means.get(m, 0) >= t for m, t in thresholds.items())
    return {"passed": passed, "means": means, "thresholds": thresholds}
